+            let mean_loss = if n_batches > 0 {
+                total_loss_sum / n_batches as f64
+            } else {
+                0.0
+            };
+            let mean_kp_loss = if n_batches > 0 {
+                kp_loss_sum / n_batches as f64
+            } else {
+                0.0
+            };
