+        Ok(TrainResult {
+            best_pck: best_pck.max(0.0),
+            best_epoch,
+            final_train_loss: training_history
+                .last()
+                .map(|l| l.train_loss)
+                .unwrap_or(0.0),
+            training_history,
+            checkpoint_path: best_checkpoint_path,
+        })
+    }
