+
+    // At least some amplitude value must differ between index 0 and 1.
+    let all_same = s0
+        .amplitude
+        .iter()
+        .zip(s1.amplitude.iter())
+        .all(|(a, b)| (a - b).abs() < 1e-7);
+
+    assert!(
+        !all_same,
+        "samples at different indices must not be identical in amplitude"
+    );
+}
